/*
 * lgamma() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly lgamma  (test_lgamma_opt.elf)
 *   2. Linked with toolchain's default lgamma       (test_lgamma_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += lgamma(vx);
#else
    double r = lgamma(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);                                   /* pole at 0 -> +Inf */
    emit(-0.0);                                  /* pole at -0 -> +Inf */
    emit_u(0x7ff8000000000000ULL);               /* qNaN */
    emit_u(0x7ff0000000000001ULL);               /* sNaN */
    emit_u(0xfff8000000000000ULL);               /* -qNaN */
    emit_u(0x7ff0000000000000ULL);               /* +Inf -> +Inf */
    emit_u(0xfff0000000000000ULL);               /* -Inf -> +Inf (reflection) */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);               /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);               /* min negative subnormal */
    emit_u(0x0008000000000000ULL);               /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);               /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);               /* max positive subnormal */
    emit_u(0x800fffffffffffffULL);               /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                               /* smallest normal: 2^-1022 */
    emit(-DBL_MIN);                              /* negative smallest normal */
    emit_u(0x0010000000000001ULL);               /* one ULP above DBL_MIN */
    emit_u(0x7fefffffffffffffULL);               /* DBL_MAX */

    /* --- Section 4: Near-zero positive inputs (6) --- */
    /* lgamma(x) ~ -ln(x) for x near 0+ */
    emit(1.0e-10);
    emit(1.0e-100);
    emit(1.0e-300);
    emit_u(0x3eb0000000000000ULL);               /* 2^-20 ~ 9.5e-7 */
    emit_u(0x3f50000000000000ULL);               /* 2^-10 ~ 9.8e-4 */
    emit_u(0x3fb0000000000000ULL);               /* 2^-4 = 0.0625 */

    /* --- Section 5: Known exact values - positive integers (8) --- */
    /* lgamma(n) = ln((n-1)!) for integer n >= 1 */
    emit(1.0);   /* lgamma(1) = 0 */
    emit(2.0);   /* lgamma(2) = 0 */
    emit(3.0);   /* lgamma(3) = ln(2) */
    emit(4.0);   /* lgamma(4) = ln(6) */
    emit(5.0);   /* lgamma(5) = ln(24) */
    emit(6.0);   /* lgamma(6) = ln(120) */
    emit(10.0);  /* lgamma(10) = ln(362880) */
    emit(20.0);  /* lgamma(20) = ln(19!) */

    /* --- Section 6: Half-integer values (8) --- */
    /* gamma(n+0.5) involves sqrt(pi); well-tested polynomial branch */
    emit(0.5);   /* lgamma(0.5) = 0.5*ln(pi) */
    emit(1.5);   /* lgamma(1.5) = 0.5*ln(pi) - ln(2) */
    emit(2.5);
    emit(3.5);
    emit(4.5);
    emit(-0.5);  /* between poles at 0 and -1 */
    emit(-1.5);  /* between poles at -1 and -2 */
    emit(-2.5);  /* between poles at -2 and -3 */

    /* --- Section 7: ULP neighbors of lgamma(x)=0 points: x=1 and x=2 (8) --- */
    emit_u(0x3fefffffffffffffULL);               /* one ULP below 1.0 */
    emit_u(0x3ff0000000000000ULL);               /* 1.0 exactly */
    emit_u(0x3ff0000000000001ULL);               /* one ULP above 1.0 */
    emit_u(0x3ff7ffffffffffffULL);               /* one ULP below 1.5 */
    emit_u(0x3ff8000000000000ULL);               /* 1.5 exactly */
    emit_u(0x3ff8000000000001ULL);               /* one ULP above 1.5 */
    emit_u(0x3fffffffffffffffULL);               /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);               /* one ULP above 2.0 */

    /* --- Section 8: Interval [1, 2] primary polynomial region (8) --- */
    emit_u(0x3ff2000000000000ULL);               /* 1.125 */
    emit_u(0x3ff4000000000000ULL);               /* 1.25 */
    emit_u(0x3ff6000000000000ULL);               /* 1.375 */
    emit_u(0x3ffa000000000000ULL);               /* 1.625 */
    emit_u(0x3ffc000000000000ULL);               /* 1.75 */
    emit_u(0x3ffe000000000000ULL);               /* 1.875 */
    emit(1.4616321449683623); /* minimum of lgamma on (0,inf), gamma'=0 */
    emit_u(0x3ff3c00000000000ULL);               /* 1.234375, mid-interval */

    /* --- Section 9: Range (2, 10] normal computation (8) --- */
    emit(2.5);
    emit(3.0);
    emit(3.5);
    emit(4.0);
    emit(5.0);
    emit(6.5);
    emit(8.0);
    emit(9.5);

    /* --- Section 10: Large positive values - Stirling approximation (8) --- */
    emit(50.0);
    emit(100.0);
    emit(1000.0);
    emit(1.0e6);
    emit(1.0e10);
    emit(1.0e15);
    emit(1.0e100);
    emit_u(0x7fe0000000000000ULL);               /* near DBL_MAX: 2^1022 */

    /* --- Section 11: Negative non-integer values between poles (9) --- */
    /* lgamma is defined between consecutive negative integers */
    emit(-0.1);   /* just left of 0 pole */
    emit(-0.9);   /* just right of -1 pole */
    emit(-1.1);   /* just left of -1 pole */
    emit(-1.9);   /* just right of -2 pole */
    emit(-2.5);   /* midpoint between -2 and -3 poles */
    emit(-3.5);   /* midpoint between -3 and -4 poles */
    emit(-4.5);   /* midpoint between -4 and -5 poles */
    emit(-10.5);  /* midpoint between -10 and -11 poles */
    emit(-100.5); /* large negative non-integer */

    /* --- Section 12: Near negative integer poles - ULP approach (8) --- */
    emit_u(0xbff0000000000002ULL);               /* -1.0 + 1 ULP (toward zero) */
    emit_u(0xbfffffffffffffffULL);               /* one ULP above -2.0 (toward zero) */
    emit_u(0xc000000000000001ULL);               /* one ULP below -2.0 */
    emit_u(0xc007ffffffffffffULL);               /* one ULP above -3.0 */
    emit_u(0xc008000000000001ULL);               /* one ULP below -3.0 */
    emit_u(0xc00fffffffffffffULL);               /* one ULP above -4.0 */
    emit_u(0xc010000000000001ULL);               /* one ULP below -4.0 */
    emit_u(0xbff0000000000001ULL);               /* two ULPs above -1.0 */

    /* --- Section 13: Transition region near x=0.5 (5) --- */
    emit_u(0x3fdffffffffffffeULL);               /* two ULPs below 0.5 */
    emit_u(0x3fdffffffffffffeULL + 1);           /* one ULP below 0.5 */
    emit_u(0x3fe0000000000000ULL);               /* 0.5 exactly */
    emit_u(0x3fe0000000000001ULL);               /* one ULP above 0.5 */
    emit(0.25);

    /* --- Section 14: Intermediate positive values [10, 50] (5) --- */
    emit(11.0);
    emit(15.0);
    emit(21.5);
    emit(30.0);
    emit(40.0);

    /* --- Section 15: Values that stress sign changes of lgamma (6) --- */
    /* lgamma changes sign near x = 1 and x = 2 from below */
    emit(0.7);
    emit(0.8);
    emit(0.9);
    emit(1.1);
    emit(1.2);
    emit(1.8);
}

/* 7. Sweep [0.5, 10] in 200 steps */
static void test_sweep(void)
{
    double lo = 0.5;
    double hi = 10.0;
    int nsteps = 200;
    double step = (hi - lo) / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (double)i * step);
}

/* 8. Sample [1, 2] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x3ff0000000000000ULL, /* 1.0 */
        0x3ff2000000000000ULL, /* 1.125 */
        0x3ff4000000000000ULL, /* 1.25 */
        0x3ff8000000000000ULL, /* 1.5 */
        0x3ffc000000000000ULL, /* 1.75 */
        0x4000000000000000ULL, /* 2.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    startPFM;
    for (int i = 0; i < 100; i++)
        g_acc += lgamma(vx + i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)g_acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

